window.CARSPECIO_SEARCH = {
    index: window.CARSPECIO_SEARCH_INDEX,

    search: function(query) {
        if (!query || query.length < 2) return [];

        const lowerQuery = query.toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '');
        return window.CARSPECIO_SEARCH_INDEX.filter(item => {
            const text = (item.name + ' ' + item.description + ' ' + (item.categoryName || item.category || '')).toLowerCase();
            return item.keywords.some(keyword => keyword.normalize('NFD').replace(/[̀-ͯ]/g, '').includes(lowerQuery)) ||
                   text.normalize('NFD').replace(/[̀-ͯ]/g, '').includes(lowerQuery);
        }).slice(0, 10);
    },

    getUrl: function(item) {
        if (item.type === 'guide') {
            return 'guias/' + item.url;
        }
        return item.url;
    }
};

// Backward-compatible alias
